        "code": "// Ornek2: Java 18 — basit dosya web sunucusu (SimpleFileServer / jwebserver, JEP 408).\n// Çalıştırma: java Ornek2.java\nimport com.sun.net.httpserver.SimpleFileServer;\nimport com.sun.net.httpserver.SimpleFileServer.OutputLevel;\nimport java.net.InetSocketAddress;\nimport java.net.URI;\nimport java.net.http.HttpClient;\nimport java.net.http.HttpRequest;\nimport java.net.http.HttpResponse;\nimport java.nio.file.Files;\nimport java.nio.file.Path;\n\npublic class Ornek2 {\n\n    public static void main(String[] args) throws Exception {\n        // Sunulacak içeriği bir geçici dizine hazırla.\n        Path kok = Files.createTempDirectory(\"jweb-\");\n        Files.writeString(kok.resolve(\"index.html\"), \"<h1>Merhaba Java 18 web sunucusu!</h1>\");\n\n        // Java 18: tek satırda statik dosya sunucusu (komut satırından 'jwebserver' olarak da var).\n        var sunucu = SimpleFileServer.createFileServer(\n                new InetSocketAddress(\"localhost\", 0), kok, OutputLevel.NONE);\n        sunucu.start();\n        int port = sunucu.getAddress().getPort();\n        System.out.println(\"Basit dosya sunucusu: http://localhost:\" + port + \"/  (kök: \" + kok.getFileName() + \")\");\n\n        // İstemciyle index.html'i iste:\n        HttpResponse<String> cevap = HttpClient.newHttpClient().send(\n                HttpRequest.newBuilder(URI.create(\"http://localhost:\" + port + \"/index.html\")).build(),\n                HttpResponse.BodyHandlers.ofString());\n        System.out.println(\"Durum: \" + cevap.statusCode() + \" | gövde: \" + cevap.body());\n\n        sunucu.stop(0);\n        Files.deleteIfExists(kok.resolve(\"index.html\"));\n        Files.deleteIfExists(kok);\n\n        System.out.println(\"\"\"\n\n                --- Java 18: basit web sunucusu (JEP 408) ---\n                SimpleFileServer / komut satırında 'jwebserver': statik dosyaları sunan minimal HTTP sunucusu.\n                Amaç ÜRETİM DEĞİL; hızlı prototipleme, test, dosya paylaşımı, öğrenme.\n                'jwebserver -p 8000' ile mevcut dizini tek komutla web'de yayınlarsın (Python'un http.server'ı gibi).\n                Programatik API (bu örnek): createFileServer(adres, kökDizin, çıktıSeviyesi) -> HttpServer.\n                Gerçek uygulama için Spring Boot / tam HttpServer kullanılır.\"\"\");\n    }\n}",
        "runnable": true,
